#!/usr/bin/env python3
"""Regenerate the autogenerated blocks of ``SK_EFT_Hawking_Inventory_Index.md``.

The Inventory Index is a hand-maintained LLM quick-reference. A handful of its
parts are *mechanical* — they restate numbers that already live in
``docs/counts.json`` (and the bundle-target registry) and therefore drift
between manual syncs. This script owns exactly those mechanical parts: it
regenerates clearly-delimited blocks bracketed by HTML-comment markers and
leaves every hand-written sentence untouched.

Autogen blocks
--------------
``AUTOGEN:counts-table``
    The §1 "Counts" table rows that are pure counts (Lean declarations through
    publication bundles). The three trailing hand-written narrative rows
    ("Phase 6r SymTFT modules" etc.) live *outside* the markers and are never
    rewritten here.

``AUTOGEN:per-family-counts``
    The §3 "**Per-family verified counts** ..." sentence. Families are derived
    dynamically from ``lean.module_names``: a module belongs to family ``X`` if
    its name starts with ``SKEFTHawking.X.`` (i.e. has a deeper segment);
    everything with no deeper segment is a top-level module. The list is NOT
    hard-coded — new sub-package families appear automatically.

``AUTOGEN:family-count-table``
    A compact family -> count table placed adjacent to the §3.1 subdirectory
    table. DESIGN CHOICE: the existing §3.1 table interleaves hand-written
    Purpose/Pointer prose with the Count column, so rewriting only its Count
    cells would be invasive and fragile (it would have to parse and rebuild
    hand-edited rows). Per the spec's "choose the less invasive option", we
    instead emit a *separate* generated table as its own autogen block and
    leave the hand-written §3.1 table completely alone. The two are easy to
    reconcile by eye and the generated one is the authoritative count source.

Data sources
------------
* ``docs/counts.json`` — every count field plus ``lean.module_names``
  (regenerated by ``scripts/update_counts.py``).
* ``scripts/sentence_state.py`` ``_VALID_BUNDLE_TARGETS`` — the canonical
  publication-bundle registry; its cardinality is the "Publication bundles"
  count (``counts.json`` carries no bundle field). Sourcing it here keeps the
  bundle row inside the autogen block instead of stranding it as a manual value.

Usage
-----
    uv run python scripts/update_inventory_index.py            # rewrite in place
    uv run python scripts/update_inventory_index.py --check    # exit nonzero if stale

The generator is idempotent: running it twice produces no diff. ``--check``
never writes; it reports a per-block stale/fresh summary and exits 1 if any
block is stale.

Conventions: uv-managed Python >=3.14, pathlib, stdlib only.
"""

from __future__ import annotations

import argparse
import json
import sys
from collections import Counter
from pathlib import Path

SCRIPT_DIR = Path(__file__).resolve().parent
PROJECT_ROOT = SCRIPT_DIR.parent
COUNTS_JSON_PATH = PROJECT_ROOT / "docs" / "counts.json"
INDEX_PATH = PROJECT_ROOT / "SK_EFT_Hawking_Inventory_Index.md"

MODULE_PREFIX = "SKEFTHawking."

# Marker tags (the HTML-comment sentinels that bracket each autogen block).
TAG_COUNTS_TABLE = "AUTOGEN:counts-table"
TAG_PER_FAMILY = "AUTOGEN:per-family-counts"
TAG_FAMILY_TABLE = "AUTOGEN:family-count-table"


def _marker_begin(tag: str) -> str:
    return f"<!-- {tag} BEGIN -->"


def _marker_end(tag: str) -> str:
    return f"<!-- {tag} END -->"


# ────────────────────────────────────────────────────────────────────────
# Data loading + grouping
# ────────────────────────────────────────────────────────────────────────

def load_counts(path: Path = COUNTS_JSON_PATH) -> dict:
    """Load and return the parsed ``counts.json`` document."""
    return json.loads(path.read_text())


def bundle_target_count() -> int:
    """Cardinality of the canonical publication-bundle registry.

    counts.json has no bundle field, so the count comes from
    ``sentence_state._VALID_BUNDLE_TARGETS`` (the same registry validate.py and
    bundle_readiness.py use). Falls back to the last-known value only if the
    import is unavailable, so the generator never hard-crashes off-tree.
    """
    if str(SCRIPT_DIR) not in sys.path:
        sys.path.insert(0, str(SCRIPT_DIR))
    try:
        from sentence_state import _VALID_BUNDLE_TARGETS  # type: ignore
        return len(_VALID_BUNDLE_TARGETS)
    except Exception:  # pragma: no cover - defensive only
        return 17


def group_families(module_names: list[str]) -> tuple[list[tuple[str, int]], int]:
    """Group module names into (family, count) pairs + the top-level count.

    A module belongs to family ``X`` iff its name is ``SKEFTHawking.X.<rest>``
    (a deeper segment exists). Modules with no deeper segment are top-level.
    Families are returned sorted by descending count, then ascending name —
    the same ordering the Index uses. Derived dynamically; nothing hard-coded.
    """
    fam: Counter[str] = Counter()
    top = 0
    for name in module_names:
        if not name.startswith(MODULE_PREFIX):
            # Defensive: a module outside the expected namespace counts as
            # top-level rather than silently vanishing.
            top += 1
            continue
        rest = name[len(MODULE_PREFIX):]
        parts = rest.split(".")
        if len(parts) >= 2:
            fam[parts[0]] += 1
        else:
            top += 1
    families = sorted(fam.items(), key=lambda kv: (-kv[1], kv[0]))
    return families, top


# ────────────────────────────────────────────────────────────────────────
# Block rendering
# ────────────────────────────────────────────────────────────────────────

def render_counts_table(counts: dict) -> str:
    """Render the §1 counts-table rows (no surrounding markers)."""
    lean = counts["lean"]
    py = counts["python"]
    ari = counts["aristotle"]
    rows = [
        ("Lean declarations (total)", str(lean["total_declarations"])),
        ("Lean theorems (total)", str(lean["theorems_total"])),
        ("Lean theorems (substantive)", str(lean["theorems_substantive"])),
        ("Lean theorems (placeholder `True := trivial`)",
         str(lean["theorems_placeholder"])),
        ("Lean modules", str(lean["modules"])),
        ("Lean definitions", str(lean["definitions"])),
        ("Lean structures", str(lean["structures"])),
        ("Lean instances", str(lean["instances"])),
        ("Lean inductives", str(lean["inductives"])),
        ("Lean axioms", f"**{lean['axioms']}** (project-local)"),
        ("Lean sorries", f"**{lean['sorry_declarations']}**"),
        ("Aristotle-proved theorems", str(ari["aristotle_proved"])),
        ("Aristotle runs", str(ari["aristotle_runs"])),
        ("Python source modules", str(py["python_modules"])),
        ("Test files", str(py["test_files"])),
        ("pytest cases", str(py["pytest_cases"])),
        ("Figures (PNG)", str(py["figures"])),
        ("Notebooks", str(py["notebooks"])),
        ("Papers (drafts)", str(py["papers"])),
        ("Publication bundles (per PAPER_STRATEGY)", str(bundle_target_count())),
    ]
    lines = ["| Metric | Value |", "|---|---:|"]
    lines += [f"| {metric} | {value} |" for metric, value in rows]
    return "\n".join(lines)


def render_per_family_sentence(counts: dict) -> str:
    """Render the §3 "Per-family verified counts" sentence (no markers)."""
    families, top = group_families(counts["lean"]["module_names"])
    fam_str = ", ".join(f"{name} {count}" for name, count in families)
    return (
        "**Per-family verified counts** (from grouping `lean.module_names`): "
        f"{fam_str}; remaining **{top} top-level** modules under "
        "`lean/SKEFTHawking/` directly. For full per-module theorem counts + "
        "key results, see `SK_EFT_Hawking_Inventory.md` Section 2. For the "
        "canonical module-name list, see `docs/counts.json` field "
        "`lean.module_names`."
    )


def render_family_table(counts: dict) -> str:
    """Render the compact family -> count table (no markers)."""
    families, top = group_families(counts["lean"]["module_names"])
    total = counts["lean"]["modules"]
    lines = [
        "**Generated family module-count table** (authoritative; derived from "
        "`lean.module_names`. The §3.1 table above is hand-maintained — reconcile "
        "its Count column against this block):",
        "",
        "| Family | Modules |",
        "|---|---:|",
    ]
    lines += [f"| `{name}` | {count} |" for name, count in families]
    lines.append(f"| _(top-level)_ | {top} |")
    lines.append(f"| **Total** | **{total}** |")
    return "\n".join(lines)


# ────────────────────────────────────────────────────────────────────────
# Marker-block splice
# ────────────────────────────────────────────────────────────────────────

def replace_block(text: str, tag: str, new_inner: str) -> str:
    """Replace the content between a tag's BEGIN/END markers.

    The markers themselves (and the blank lines padding them) are preserved;
    only the inner body is swapped. Raises if the markers are missing or
    malformed so silent no-ops can't mask a broken file.
    """
    begin = _marker_begin(tag)
    end = _marker_end(tag)
    bi = text.find(begin)
    ei = text.find(end)
    if bi == -1 or ei == -1:
        raise ValueError(f"markers for {tag!r} not found in index file")
    if ei < bi:
        raise ValueError(f"END before BEGIN for {tag!r} in index file")
    # Splice: keep marker lines, put a blank line, the body, a blank line.
    before = text[: bi + len(begin)]
    after = text[ei:]
    return f"{before}\n{new_inner}\n{after}"


def build_blocks(counts: dict) -> dict[str, str]:
    """Map each tag to its freshly rendered inner content."""
    return {
        TAG_COUNTS_TABLE: render_counts_table(counts),
        TAG_PER_FAMILY: render_per_family_sentence(counts),
        TAG_FAMILY_TABLE: render_family_table(counts),
    }


def regenerate_text(current: str, counts: dict) -> str:
    """Return the index text with every autogen block refreshed."""
    out = current
    for tag, inner in build_blocks(counts).items():
        out = replace_block(out, tag, inner)
    return out


# ────────────────────────────────────────────────────────────────────────
# Public entry points (imported by validate.py + tests)
# ────────────────────────────────────────────────────────────────────────

def compute_stale(index_path: Path = INDEX_PATH,
                  counts_path: Path = COUNTS_JSON_PATH) -> tuple[bool, str]:
    """Return ``(is_stale, summary)`` without writing anything.

    ``is_stale`` is True if regenerating any autogen block would change the
    file. ``summary`` names the stale block(s) or confirms freshness.
    Missing markers / files surface as a stale result with a diagnostic.
    """
    if not index_path.exists():
        return True, f"index file missing: {index_path}"
    if not counts_path.exists():
        return True, f"counts.json missing: {counts_path}"

    current = index_path.read_text()
    counts = load_counts(counts_path)

    stale_tags: list[str] = []
    for tag, inner in build_blocks(counts).items():
        begin, end = _marker_begin(tag), _marker_end(tag)
        bi = current.find(begin)
        ei = current.find(end)
        if bi == -1 or ei == -1:
            stale_tags.append(f"{tag} (markers missing)")
            continue
        existing_inner = current[bi + len(begin): ei].strip("\n")
        if existing_inner != inner:
            stale_tags.append(tag)

    if stale_tags:
        return True, "stale block(s): " + ", ".join(stale_tags)
    return False, "all autogen blocks fresh"


def write_regenerated(index_path: Path = INDEX_PATH,
                      counts_path: Path = COUNTS_JSON_PATH) -> bool:
    """Rewrite the index in place. Returns True iff the file changed."""
    current = index_path.read_text()
    counts = load_counts(counts_path)
    new = regenerate_text(current, counts)
    if new != current:
        index_path.write_text(new)
        return True
    return False


# ────────────────────────────────────────────────────────────────────────
# CLI
# ────────────────────────────────────────────────────────────────────────

def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        description="Regenerate autogen blocks in "
                    "SK_EFT_Hawking_Inventory_Index.md from docs/counts.json.")
    parser.add_argument(
        "--check", action="store_true",
        help="Do not write; exit nonzero with a diff summary if any block is "
             "stale.")
    args = parser.parse_args(argv)

    if args.check:
        stale, summary = compute_stale()
        if stale:
            print(f"STALE: {summary}")
            print("Run: uv run python scripts/update_inventory_index.py")
            return 1
        print(f"FRESH: {summary}")
        return 0

    changed = write_regenerated()
    if changed:
        print("Updated SK_EFT_Hawking_Inventory_Index.md autogen blocks.")
    else:
        print("No change — autogen blocks already fresh.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
